from PhseXlib.addres import addres_transformer,is_addres

def enable_security_module(func):
    def warp_func(*args):
        print(func,":",args)
        for i in args:
            if is_addres(addres_transformer(i)):
                print(f"{i} is addres")
            else:
                print(f"{i} not addres")
        return func(*args)
    return warp_func